 inferScope } from \"../util/infer-scope\";\nimport type { ProvidesHelp } from \"cmd-ts/dist/esm/helpdoc\";\nimport chalk from \"chalk\";\n\nconst project = cmd.option({\n  long: \"project\",\n  type: { ...cmd.optional(cmd.string), displayName: \"my-project\" },\n  description:\n    \"The project name or ID to associate with the command. Can be inferred from VERCEL_OIDC_TOKEN.\",\n});\n\n/** Parser for the `--team` option. */\nconst teamParser = cmd.option({\n  long: \"team\",\n  type: { ...cmd.optional(cmd.string), displayName: \"my-team\" },\n});\n/** Parser for the `--scope` option. */\nconst scopeParser = cmd.option({\n  long: \"scope\",\n  type: { ...cmd.optional(cmd.string), displayName: \"my-team\" },\n  description:\n    \"The scope/team to associate with the command. Can be inferred from VERCEL_OIDC_TOKEN. [alias: --team]\",\n});\n\n/** Parser for the `--scope` option that falls back to `--team` if not provided. */\nconst team: typeof scopeParser = {\n  ...scopeParser,\n  register(opts) {\n    scopeParser.register?.(opts);\n    teamParser.register?.(opts);\n  },\n  async parse(context) {\n    const [scope, team] = await Promise.all([\n      scopeParser.parse(context),\n      teamParser.parse(context),\n    ]);\n\n    if (scope._tag !== \"error\" && typeof scope.value === \"undefined\") {\n      if (team._tag !== \"error\" && team.value) {\n        return team;\n      } else if (team._tag === \"error\") {\n        return team;\n      }\n    }\n\n    return scope;\n  },\n};\n\n/**\n * Combining multiple argument parsing into a single \"scope\" argument\n * that includes token, project, and team.\n * If project or team are not provided, they will be inferred.\n */\nexport const scope: ArgParser<{\n  token: string;\n  project: string;\n  team: string;\n  projectSlug?: string;\n  teamSlug?: string;\n}> &\n  ProvidesHelp = {\n  register(ctx) {\n    token.register?.(ctx);\n    project.register?.(ctx);\n    team.register?.(ctx);\n  },\n  async parse(context) {\n    const t = await token.parse(context);\n    if (t._tag === \"error\") {\n      return t;\n    }\n\n    // We want to find all the arguments that `--project` or `--team` are\n    // visiting, so the errors will be nicer.\n    const visited = new Set(context.visitedNodes);\n    let [projectId, teamId] = await Promise.all([\n      project.parse(context),\n      team.parse(context),\n    ]);\n    const nodes = Array.from(context.visitedNodes).filter(\n      (x) => !visited.has(x),\n    );\n\n    if (projectId._tag === \"error\") {\n      return projectId;\n    }\n\n    if (teamId._tag === \"error\") {\n      return teamId;\n    }\n\n    let projectSlug: string | undefined;\n    let teamSlug: string | undefined;\n\n    if (\n      typeof projectId.value === \"undefined\" ||\n      typeof teamId.value === \"undefined\"\n    ) {\n      try {\n        const scope = await inferScope({\n          token: t.value,\n          team: teamId.value,\n        });\n        projectId.value ??= scope.project;\n        teamId.value ??= scope.owner;\n        projectSlug = scope.projectSlug;\n        teamSlug = scope.ownerSlug;\n      } catch (err) {\n        return {\n          _tag: \"error\",\n          error: {\n            errors: [\n              {\n                nodes,\n                message: [\n                  `Could not determine team/project scope: ${(err as Error).message}.`,\n                  `${chalk.bold(\"hint:\")} Specify explicitly with --scope TEAM_SLUG --project PROJECT_NAME, or set VERCEL_OIDC_TOKEN.`,\n                  \"╰▶ Docs: https://vercel.com/docs/sandbox\",\n                ].join(\"\\n\"),\n              },\n            ],\n          },\n        };\n      }\n    }\n\n    return {\n      _tag: \"ok\",\n      value: {\n        token: t.value,\n        project: projectId.value,\n        team: teamId.value,\n        projectSlug,\n        teamSlug,\n      },\n    };\n  },\n  helpTopics() {\n    return [\n      ...token.helpTopics(),\n      ...project.helpTopics(),\n      ...team.helpTopics(),\n    ].map((x) => ({\n      ...x,\n      category: \"Auth & Scope\",\n    }));\n  },\n};\n","{\n  \"name\": \"sandbox\",\n  \"description\": \"Command line interface for Vercel Sandbox\",\n  \"version\": \"2.5.6\",\n  \"scripts\": {\n    \"clean\": \"rm -rf node_modules dist\",\n    \"sandbox\": \"ts-node ./src/sandbox.ts\",\n    \"build\": \"tsdown\",\n    \"vercel-build\": \"ts-node ./scripts/create-preview-deployment-tgz.ts\",\n    \"test\": \"vitest\",\n    \"example-whoami\": \"ts-node ./src/example-whoami.ts\",\n    \"example-next\": \"ts-node ./src/example-next.ts\",\n    \"example-flask\": \"ts-node ./src/example-flask.ts\",\n    \"typecheck\": \"tsc --noEmit\",\n    \"generate-docs\": \"ts-node ./scripts/print-usage.ts > docs/index.md\",\n    \"version:bump\": \"pnpm generate-docs\"\n  },\n  \"keywords\": [\n    \"vercel\",\n    \"sandbox\",\n    \"cli\"\n  ],\n  \"main\": \"./dist/index.mjs\",\n  \"bin\": {\n    \"sandbox\": \"./bin/sandbox.mjs\",\n    \"sbx\": \"./bin/sandbox.mjs\"\n  },\n  \"files\": [\n    \"bin\",\n    \"README.md\",\n    \"dist\"\n  ],\n  \"homepage\": \"https://vercel.com/docs/vercel-sandbox/cli-reference\",\n  \"repository\": {\n    \"type\": \"git\",\n    \"url\": \"https://github.com/vercel/sandbox.git\",\n    \"directory\": \"packages/sandbox\"\n  },\n  \"license\": \"Apache-2.0\",\n  \"dependencies\": {\n    \"@vercel/sandbox\": \"workspace:*\",\n    \"debug\": \"^4.4.1\",\n    \"zod\": \"^4.1.1\"\n  },\n  \"devDependencies\": {\n    \"@types/debug\": \"^4.1.12\",\n    \"@types/ms\": \"^2.1.0\",\n    \"@types/node\": \"^22.15.12\",\n    \"@vercel/oidc\": \"^3.2.0\",\n    \"@vercel/pty-tunnel\": \"workspace:*\",\n    \"@vercel/pty-tunnel-server\": \"workspace:*\",\n    \"@vercel/sandbox\": \"workspace:*\",\n    \"chalk\": \"^5.6.0\",\n    \"cmd-ts\": \"0.15.0\",\n    \"date-fns\": \"^4.1.0\",\n    \"dotenv-flow\": \"^4.1.0\",\n    \"listr2\": \"^9.0.2\",\n    \"ms\": \"^2.1.3\",\n    \"open\": \"^10.2.0\",\n    \"ora\": \"^8.2.0\",\n    \"tsdown\": \"catalog:\",\n    \"vitest\": \"catalog:\",\n    \"xdg-app-paths\": \"5.1.0\"\n  }\n}\n","import chalk from \"chalk\";\n\nexport class StyledError extends Error {\n  name = \"StyledError\";\n  constructor(message: string, cause?: unknown) {\n    super(chalk.red(message), { cause });\n  }\n}\n","import { Sandbox, APIError, Snapshot } from \"@vercel/sandbox\";\nimport { version } from \"./pkg\";\nimport chalk from \"chalk\";\nimport { tmpdir } from \"node:os\";\nimport Path from \"node:path\";\nimport { writeFile } from \"node:fs/promises\";\nimport { StyledError } from \"./error\";\nimport { z } from \"zod\";\n\n/**\n * A {@link Sandbox} wrapper that adds user-agent headers and error handling.\n */\nexport const sandboxClient: Pick<typeof Sandbox, \"get\" | \"list\" | \"create\"> = {\n  get: (params) =>\n    withErrorHandling(Sandbox.get({ fetch: fetchWithUserAgent, ...params })),\n  create: (params) =>\n    withErrorHandling(Sandbox.create({ fetch: fetchWithUserAgent, ...params })),\n  list: (params) =>\n    withErrorHandling(\n      Sandbox.list({ fetch: fetchWithUserAgent, ...params } as typeof params),\n    ),\n};\n\nexport const snapshotClient: Pick<typeof Snapshot, \"get\" | \"list\"> = {\n  list: (params) =>\n    withErrorHandling(Snapshot.list({ fetch: fetchWithUserAgent, ...params })),\n  get: (params) => withErrorHandling(Snapshot.get({ ...params })),\n};\n\nconst fetchWithUserAgent: typeof globalThis.fetch = (input, init) => {\n  const headers = new Headers(\n    init?.headers ??\n      (input && typeof input === \"object\" && \"headers\" in input\n        ? input?.headers\n        : {}),\n  );\n  let agent = `vercel/sandbox-cli/${version}`;\n\n  const existingAgent = headers.get(\"user-agent\");\n  if (existingAgent) {\n    agent += ` ${existingAgent}`;\n  }\n\n  headers.set(\"user-agent\", agent);\n\n  return fetch(input, { ...init, headers });\n};\n\nasync function withErrorHandling<T>(promise: Promise<T>) {\n  try {\n    return await promise;\n  } catch (error) {\n    if (error instanceof APIError) {\n      return await handleApiError(error);\n    }\n    throw error;\n  }\n}\n\nasync function handleApiError(error: APIError<unknown>): Promise<never> {\n  const tmpPath = await writeResponseToTemp(error);\n  const status = error.response.status;\n  const parsedError = ApiErrorResponse.safeParse(error.json);\n  const message = parsedError.data?.error.message ?? getErrorMessage(status);\n  const lines = [\n    message,\n    `├▶ requested url: ${error.response.url}`,\n    `├▶ status code: ${status} ${error.response.statusText}`,\n    `╰▶ ${chalk.bold(\"hint:\")} the full response buffer is stored in ${chalk.italic(tmpPath)}`,\n  ];\n  throw new StyledError(lines.join(\"\\n\"), error);\n}\n\nconst ApiErrorResponse = z.object({\n  error: z.object({\n    message: z.string(),\n  }),\n});\n\nfunction getErrorMessage(status: number): string {\n  if (status === 401 || status === 403) {\n    return \"Sandbox API request failed due to authentication. Check your token or run `sandbox login`.\";\n  }\n  if (status === 404) {\n    return \"Sandbox API request failed: resource not found.\";\n  }\n  if (status >= 500) {\n    return \"Sandbox API responded with a server error. Please try again.\";\n  }\n  return \"Sandbox API request failed.\";\n}\n\nasync function writeResponseToTemp({\n  response,\n  text,\n}: APIError<unknown>): Promise<string> {\n  const unique = [process.pid, process.hrtime.bigint()]\n    .map((x) => x.toString(36))\n    .join(\"\");\n  const tmpPath = Path.join(tmpdir(), `sandbox-cli-response-${unique}.http`);\n  const buffers = [] as Buffer[];\n  buffers.push(Buffer.from(`${response.url}\\r\\n`));\n  buffers.push(Buffer.from(`${response.status} ${response.statusText}\\r\\n`));\n  for (const [key, value] of response.headers) {\n    buffers.push(Buffer.from(`${key}: ${value}\\r\\n`));\n  }\n  buffers.push(Buffer.from(`\\r\\n`));\n  if (text) {\n    buffers.push(Buffer.from(text));\n  }\n  await writeFile(tmpPath, Buffer.concat(buffers));\n  return tmpPath;\n}\n","import * as cmd from \"cmd-ts\";\nimport chalk from \"chalk\";\n\nexport const snapshotId = cmd.extendType(cmd.string, {\n  displayName: \"snapshot_id\",\n  description: \"The ID of the snapshot\",\n  async from(s) {\n    if (!s.startsWith(\"snap_\")) {\n      throw new Error(\n        [\n          `Malformed snapshot ID: \"${s}\".`,\n          `${chalk.bold(\"hint:\")} Snapshot IDs must start with 'snap_' (e.g., snap_abc123def456).`,\n        ].join(\"\\n\"),\n      );\n    }\n    return s;\n  },\n});\n","import * as cmd from \"cmd-ts\";\nimport chalk from \"chalk\";\n\nexport const sandboxId = cmd.extendType(cmd.string, {\n  displayName: \"sandbox_id\",\n  description: \"The ID of the sandbox to execute the command in\",\n  async from(s) {\n    if (!s.startsWith(\"sbx_\")) {\n      throw new Error(\n        [\n          `Malformed sandbox ID: \"${s}\".`,\n          `${chalk.bold(\"hint:\")} Sandbox IDs must start with 'sbx_' (e.g., sbx_abc123def456).`,\n          \"╰▶ run `sandbox list` to see available sandboxes.\",\n        ].join(\"\\n\"),\n      );\n    }\n\n    return s;\n  },\n});\n","'use strict';\n\nconst BINARY_TYPES = ['nodebuffer', 'arraybuffer', 'fragments'];\nconst hasBlob = typeof Blob !== 'undefined';\n\nif (hasBlob) BINARY_TYPES.push('blob');\n\nmodule.exports = {\n  BINARY_TYPES,\n  EMPTY_BUFFER: Buffer.alloc(0),\n  GUID: '258EAFA5-E914-47DA-95CA-C5AB0DC85B11',\n  hasBlob,\n  kForOnEventAttribute: Symbol('kIsForOnEventAttribute'),\n  kListener: Symbol('kListener'),\n  kStatusCode: Symbol('status-code'),\n  kWebSocket: Symbol('websocket'),\n  NOOP: () => {}\n};\n","'use strict';\n\nconst { EMPTY_BUFFER } = require('./constants');\n\nconst FastBuffer = Buffer[Symbol.species];\n\n/**\n * Merges an array of buffers into a new buffer.\n *\n * @param {Buffer[]} list The array of buffers to concat\n * @param {Number} totalLength The total length of buffers in the list\n * @return {Buffer} The resulting buffer\n * @public\n */\nfunction concat(list, totalLength) {\n  if (list.length === 0) return EMPTY_BUFFER;\n  if (list.length === 1) return list[0];\n\n  const target = Buffer.allocUnsafe(totalLength);\n  let offset = 0;\n\n  for (let i = 0; i < list.length; i++) {\n    const buf = list[i];\n    target.set(buf, offset);\n    offset += buf.length;\n  }\n\n  if (offset < totalLength) {\n    return new FastBuffer(target.buffer, target.byteOffset, offset);\n  }\n\n  return target;\n}\n\n/**\n * Masks a buffer using the given mask.\n *\n * @param {Buffer} source The buffer to mask\n * @param {Buffer} mask The mask to use\n * @param {Buffer} output The buffer where to store the result\n * @param {Number} offset The offset at which to start writing\n * @param {Number} length The number of bytes to mask.\n * @public\n */\nfunction _mask(source, mask, output, offset, length) {\n  for (let i = 0; i < length; i++) {\n    output[offset + i] = source[i] ^ mask[i & 3];\n  }\n}\n\n/**\n * Unmasks a buffer using the given mask.\n *\n * @param {Buffer} buffer The buffer to unmask\n * @param {Buffer} mask The mask to use\n * @public\n */\nfunction _unmask(buffer, mask) {\n  for (let i = 0; i < buffer.length; i++) {\n    buffer[i] ^= mask[i & 3];\n  }\n}\n\n/**\n * Converts a buffer to an `ArrayBuffer`.\n *\n * @param {Buffer} buf The buffer to convert\n * @return {ArrayBuffer} Converted buffer\n * @public\n */\nfunction toArrayBuffer(buf) {\n  if (buf.length === buf.buffer.byteLength) {\n    return buf.buffer;\n  }\n\n  return buf.buffer.slice(buf.byteOffset, buf.byteOffset + buf.length);\n}\n\n/**\n * Converts `data` to a `Buffer`.\n *\n * @param {*} data The data to convert\n * @return {Buffer} The buffer\n * @throws {TypeError}\n * @public\n */\nfunction toBuffer(data) {\n  toBuffer.readOnly = true;\n\n  if (Buffer.isBuffer(data)) return data;\n\n  let buf;\n\n  if (data instanceof ArrayBuffer) {\n    buf = new FastBuffer(data);\n  } else if (ArrayBuffer.isView(data)) {\n    buf = new FastBuffer(data.buffer, data.byteOffset, data.byteLength);\n  } else {\n    buf = Buffer.from(data);\n    toBuffer.readOnly = false;\n  }\n\n  return buf;\n}\n\nmodule.exports = {\n  concat,\n  mask: _mask,\n  toArrayBuffer,\n  toBuffer,\n  unmask: _unmask\n};\n\n/* istanbul ignore else  */\nif (!process.env.WS_NO_BUFFER_UTIL) {\n  try {\n    const bufferUtil = require('bufferutil');\n\n    module.exports.mask = function (source, mask, output, offset, length) {\n      if (length < 48) _mask(source, mask, output, offset, length);\n      else bufferUtil.mask(source, mask, output, offset, length);\n    };\n\n    module.exports.unmask = function (buffer, mask) {\n      if (buffer.length < 32) _unmask(buffer, mask);\n      else bufferUtil.unmask(buffer, mask);\n    };\n  } catch (e) {\n    // Continue regardless of the error.\n  }\n}\n","'use strict';\n\nconst kDone = Symbol('kDone');\nconst kRun = Symbol('kRun');\n\n/**\n * A very simple job queue with adjustable concurrency. Adapted from\n * https://github.com/STRML/async-limiter\n */\nclass Limiter {\n  /**\n   * Creates a new `Limiter`.\n   *\n   * @param {Number} [concurrency=Infinity] The maximum number of jobs allowed\n   *     to run concurrently\n   */\n  constructor(concurrency) {\n    this[kDone] = () => {\n      this.pending--;\n      this[kRun]();\n    };\n    this.concurrency = concurrency || Infinity;\n    this.jobs = [];\n    this.pending = 0;\n  }\n\n  /**\n   * Adds a job to the queue.\n   *\n   * @param {Function} job The job to run\n   * @public\n   */\n  add(job) {\n    this.jobs.push(job);\n    this[kRun]();\n  }\n\n  /**\n   * Removes a job from the queue and runs it if possible.\n   *\n   * @private\n   */\n  [kRun]() {\n    if (this.pending === this.concurrency) return;\n\n    if (this.jobs.length) {\n      const job = this.jobs.shift();\n\n      this.pending++;\n      job(this[kDone]);\n    }\n  }\n}\n\nmodule.exports = Limiter;\n","'use strict';\n\nconst zlib = require('zlib');\n\nconst bufferUtil = require('./buffer-util');\nconst Limiter = require('./limiter');\nconst { kStatusCode } = require('./constants');\n\nconst FastBuffer = Buffer[Symbol.species];\nconst TRAILER = Buffer.from([0x00, 0x00, 0xff, 0xff]);\nconst kPerMessageDeflate = Symbol('permessage-deflate');\nconst kTotalLength = Symbol('total-length');\nconst kCallback = Symbol('callback');\nconst kBuffers = Symbol('buffers');\nconst kError = Symbol('error');\n\n//\n// We limit zlib concurrency, which prevents severe memory fragmentation\n// as documented in https://github.com/nodejs/node/issues/8871#issuecomment-250915913\n// and https://github.com/websockets/ws/issues/1202\n//\n// Intentionally global; it's the global thread pool that's an issue.\n//\nlet zlibLimiter;\n\n/**\n * permessage-deflate implementation.\n */\nclass PerMessageDeflate {\n  /**\n   * Creates a PerMessageDeflate instance.\n   *\n   * @param {Object} [options] Configuration options\n   * @param {(Boolean|Number)} [options.clientMaxWindowBits] Advertise support\n   *     for, or request, a custom client window size\n   * @param {Boolean} [options.clientNoContextTakeover=false] Advertise/\n   *     acknowledge disabling of client context takeover\n   * @param {Number} [options.concurrencyLimit=10] The number of concurrent\n   *     calls to zlib\n   * @param {(Boolean|Number)} [options.serverMaxWindowBits] Request/confirm the\n   *     use of a custom server window size\n   * @param {Boolean} [options.serverNoContextTakeover=false] Request/accept\n   *     disabling of server context takeover\n   * @param {Number} [options.threshold=1024] Size (in bytes) below which\n   *     messages should not be compressed if context takeover is disabled\n   * @param {Object} [options.zlibDeflateOptions] Options to pass to zlib on\n   *     deflate\n   * @param {Object} [options.zlibInflateOptions] Options to pass to zlib on\n   *     inflate\n   * @param {Boolean} [isServer=false] Create the instance in either server or\n   *     client mode\n   * @param {Number} [maxPayload=0] The maximum allowed message length\n   */\n  constructor(options, isServer, maxPayload) {\n    this._maxPayload = maxPayload | 0;\n    this._options = options || {};\n    this._threshold =\n      this._options.threshold !== undefined ? this._options.threshold : 1024;\n    this._isServer = !!isServer;\n    this._deflate = null;\n    this._inflate = null;\n\n    this.params = null;\n\n    if (!zlibLimiter) {\n      const concurrency =\n        this._options.concurrencyLimit !== undefined\n          ? this._options.concurrencyLimit\n          : 10;\n      zlibLimiter = new Limiter(concurrency);\n    }\n  }\n\n  /**\n   * @type {String}\n   */\n  static get extensionName() {\n    return 'permessage-deflate';\n  }\n\n  /**\n   * Create an extension negotiation offer.\n   *\n   * @return {Object} Extension parameters\n   * @public\n   */\n  offer() {\n    const params = {};\n\n    if (this._options.serverNoContextTakeover) {\n      params.server_no_context_takeover = true;\n    }\n    if (this._options.clientNoContextTakeover) {\n      params.client_no_context_takeover = true;\n    }\n    if (this._options.serverMaxWindowBits) {\n      params.server_max_window_bits = this._options.serverMaxWindowBits;\n    }\n    if (this._options.clientMaxWindowBits) {\n      params.client_max_window_bits = this._options.clientMaxWindowBits;\n    } else if (this._options.clientMaxWindowBits == null) {\n      params.client_max_window_bits = true;\n    }\n\n    return params;\n  }\n\n  /**\n   * Accept an extension negotiation offer/response.\n   *\n   * @param {Array} configurations The extension negotiation offers/reponse\n   * @return {Object} Accepted configuration\n   * @public\n   */\n  accept(configurations) {\n    configurations = this.normalizeParams(configurations);\n\n    this.params = this._isServer\n      ? this.acceptAsServer(configurations)\n      : this.acceptAsClien